const evt = $json;
const t = evt.event_type || 'unknown';
const ts = new Date((evt.timestamp || 0) * 1000).toISOString();
return [{ json: { ...evt, _routed_type: t, _ts: ts } }];

const evt = $json;
console.log('Scene transition:', JSON.stringify(evt));
return [{ json: { logged: true, from: evt.from_scene, to: evt.to_scene, ts: evt._ts } }];

const input = $json || {};
const nowIso = new Date().toISOString();
const summary = input.summary || input.text || input.context || 'm5 mesh intake event';
const tongue = (input.tongue || 'KO').toUpperCase();
const eventType = input.event_type || input.eventType || 'mesh_intake';
const source = input.source || input.source_system || 'n8n';

const metadata = {
  run_id: input.run_id || `m5-${Date.now()}`,
  source_system: source,
  mesh_node: input.mesh_node || 'm5.funnel.intake',
  decision_hint: input.decision || 'UNKNOWN',
  published_at_utc: nowIso,
  confidence: input.confidence ?? null,
  tags: input.tags || []
};

return [{
  json: {
    event_type: eventType,
    summary,
    outcome: input.outcome || input.response || 'captured',
    tongue,
    source_system: source,
    record_id: input.record_id || `${source}-${Date.now()}`,
    metadata
  }
}];

const update = $json.body || $json;
const message = update.message || update.edited_message || update.channel_post || {};
const chatId = message.chat?.id ?? null;
if (!chatId) {
  return [];
}

const msg = String(message.text || '').trim();
let mode = 'dispatch';
let provider = 'huggingface';
let prompt = msg;
const lower = msg.toLowerCase();

if (lower === '/status') {
  mode = 'status';
  prompt = 'status';
} else if (lower.startsWith('/grok ')) {
  provider = 'xai';
  prompt = msg.slice(6).trim();
} else if (lower.startsWith('/claude ')) {
  provider = 'anthropic';
  prompt = msg.slice(8).trim();
} else if (lower.startsWith('/gpt ')) {
  provider = 'openai';
  prompt = msg.slice(5).trim();
} else if (lower.startsWith('/hf ')) {
  provider = 'huggingface';
  prompt = msg.slice(4).trim();
}

if (!prompt) {
  prompt = 'hello';
}

return [{
  json: {
    chat_id: chatId,
    mode,
    provider,
    prompt,
    original: msg,
    update_id: update.update_id || null
  }
}];

const p = $json.providers || {};
const line = (k, v) => `${k}: ${v?.configured ? 'on' : 'off'} (${v?.default_model || '-'})`;
const text = [
  'SCBE Provider Status',
  line('openai', p.openai),
  line('anthropic', p.anthropic),
  line('xai', p.xai),
  line('huggingface', p.huggingface),
  `zapier: ${$json.zapier?.configured ? 'on' : 'off'}`
].join('\n');
return [{ json: { text } }];

let text = String($json.text || '').trim();
if (!text) {
  text = 'No text response from provider.';
}
if (text.length > 3500) {
  text = text.slice(0, 3500) + '\n...[truncated]';
}
return [{ json: { text } }];

